import { useCart } from "@ai-whisperers/commerce/cart/cart-context"
import { CartEmptyState } from "@/components/ui"
import { useState, useEffect, useRef } from "react"
import Link from "next/link"
import Image from "next/image"
import { SafeImage } from "@/components/safe-image"
import { generateCheckoutMessage, CheckoutCustomer } from "@/lib/checkout-message"

export function CartSidebar({ open, onClose }: { open: boolean; onClose: () => void }) {
  const [isClosing, setIsClosing] = useState(false)
  const [showCheckoutForm, setShowCheckoutForm] = useState(false)
  const [customer, setCustomer] = useState<CheckoutCustomer>({
    name: "",
    phone: "",
    city: "",
    ruc: "",
  })
  const nameInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (!open) return
    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") handleClose() }
    document.addEventListener("keydown", handler)
    document.body.style.overflow = "hidden"
    return () => {
      document.removeEventListener("keydown", handler)
      document.body.style.overflow = ""
    }
  }, [open])

  useEffect(() => {
    if (showCheckoutForm && nameInputRef.current) {
      nameInputRef.current.focus()
    }
  }, [showCheckoutForm])

  const { items, removeItem, updateQuantity, total, clearCart } = useCart()

  const formatGs = (n: number) => "Gs. " + n.toLocaleString("es-PY")

  const handleClose = () => {
    setIsClosing(true)
    setShowCheckoutForm(false)
    setTimeout(() => {
      setIsClosing(false)
      onClose()
    }, 200)
  }

  const handleCheckoutWhatsApp = () => {
    const msg = encodeURIComponent(generateCheckoutMessage(items, total, customer))
    const whatsappNumber = "595984009751"
    window.open(`https://wa.me/${whatsappNumber}?text=${msg}`, "_blank")
    setShowCheckoutForm(false)
  }"}

